        [HttpPost]
        public ActionResult ValidateEmailAlerts(int pptq, int qids)
        {
            var q = db.pr_getQuestion(qids).First();
            var list = db.pr_validateEmailAlertListQuestionResponseByPPTQ(pptq, q.emailAlertList.Split(new string[] { "where:" }, StringSplitOptions.RemoveEmptyEntries)[1].Replace(";", "").Trim() + ";").ToList();

            var qid = Convert.ToInt32(q.emailAlertList.Split(new char[] { '[', ']' })[1]);
            var a = 74;
            if (list.Count > 0) { a = 75; }
            db.pr_addPartnerPartnertypeTouchpointQuestionnaireQuestionResponse2(qid, a, "Automated", null, null, DateTime.Now, 0, 0, pptq);

            if (list.Count == 0)
                return Json(new { success = true });
            else
            {
                string message = "Your online [touchpoint.title] questionnaire has been submitted, however, it is currently \"pending approval\" due to the response received for the following clause(s) listed:<br/>";
                string qsss = "";
                foreach (var item in list)
                {
                    qsss += db.pr_getQuestionTitle(item.Question).First() + "<br/>";
                }

                message += qsss;

                var pptqItem = db.pr_getPartnerPartnertypeTouchpointQuestionnaire(pptq).FirstOrDefault();
                var qresponse = q;
                string t = "";

                try
                {
                    t = pptqItem.partnerTypeTouchpointQuestionnaire1.touchpoint1.title;
                }
                catch { }

                message = message.Replace("[touchpoint.title]", t);

                var choices = q.emailAlertList.Split(new char[] { ';' });
                var email = choices[0].Split(':')[1];

                var pptqObj = db.pr_getPartnerPartnertypeTouchpointQuestionnaireByAccessCodeForPDF(pptqItem.accesscode).FirstOrDefault();
                var qnextId = choices[1].Replace("[", "").Replace("]", "");
                var baseUri = new Uri(Request.Url.GetLeftPart(UriPartial.Authority));
                EmailHelper.SendEmailAlertWhere(pptqItem.partner1, pptqObj, pptqItem.accesscode, email, pptq, q.id, qnextId, qsss, baseUri, Url, Request.Url.ToString());
                return Json(new { success = false, message });
            }
        }



