        [HttpPost]
        public ActionResult validateNics(int q, int val)
        {
            var res = db.pr_getSbaSizingStandardNAICS(val).FirstOrDefault();
            string message = "Please be advised that [NAICS] is not valid and you should select LARGE BUSINESS in order to remain compliant.";

            if (res == null)
            {
                return Json(new { message = message.Replace("[NAICS]", val.ToString()), success = true });
            }
            var question = db.pr_getQuestion(q).FirstOrDefault();
            if (question == null || string.IsNullOrEmpty(question.commentBoxTxt)) return Json(new { success = true });

            List<string> arr = question.commentBoxTxt.Split("\r\n").ToList();
            if (arr[0].Contains("<> 0") && res.revenue != 0)
                message = arr[1];
            else message = arr[3];

            return Json(new { message = message.Replace("[Description]", res.description).Replace("[NAICS]", (res.NAICS ?? 0).ToString()).Replace("[employee]", (res.employee ?? 0).ToString()).Replace("[revenue]", (res.revenue ?? 0).ToString()), success = false });
        }

        public ActionResult RemoveItemsByQid(int pptqQR, string jumpTo)
        {
            var accessCode = Session["accessCode"] != null ? Session["accessCode"].ToString() : "";
            var pptqObj = db.pr_getPartnerPartnertypeTouchpointQuestionnaireByAccessCodeForPDF(accessCode).FirstOrDefault();
            int pptq = pptqObj.id;

            var qid = db.pr_getQuestionnaireByAccesscode(accessCode).First().id;
            var tts = db.pr_getQuestionByQuestionnaire(qid).ToList();

            var arr1 = jumpTo.Split(new string[] { ";" }, StringSplitOptions.RemoveEmptyEntries);
            string qstartTitle = tts.Where(o => o.id == pptqQR).First().title;
            List<int> val = new List<int>();
            List<int> nextQst = new List<int>();
            List<string> messages = new List<string>();
            List<string> qendTitle = new List<string>();
            if (arr1.Length > 0)
            {
                foreach (string s in arr1)
                {
                    int v1 = -1;
                    int nq = -1;
                    string msg = "";
                    try
                    {
                        var str = s.Split('&')[0].Replace(pptqQR.ToString() + "=", "");
                        v1 = Convert.ToInt32(str);
                        if (v1 == 0) v1 = 75;
                        if (v1 == 1) v1 = 74;
                        nq = Convert.ToInt32(s.Split(':')[1]);
                        var v = db.pr_removePartnerPartnertypeTouchpointQuestionnaireQuestionResponseByPPTQAndQuestion(
                            pptq, pptqQR, nq).Select(o => o.question).ToList();
                        msg = string.Join(", ", tts.Where(o => v.Contains(o.id)).Select(o => o.title).ToList());
                    }
                    catch { }
                    if (v1 != -1 && nq != -1)
                    {
                        val.Add(v1);
                        nextQst.Add(nq);
                        messages.Add(msg);
                        string title = "";
                        var v = tts.Where(o => o.id == nq).FirstOrDefault();
                        if (v != null) title = v.title;
                        qendTitle.Add(title);
                    }
                }
            }

            return Json(new
            {
                messages = messages,
                qstart = pptqQR,
                qend = nextQst,
                pptq = pptq,
                val = val,
                qstartTitle,
                qendTitle
            }, JsonRequestBehavior.AllowGet);
        }

