                    //else
                    //    objViewBagModel.QUESTIONNAIRE_VIDEO = CMS.QUESTIONNAIRE_VIDEO.Substring(0, 15);
                }
                ////IMG_HEADER_LINK
                cmd = questionnairCmsAll.FirstOrDefault(q => q.description == CMS.REDIRECT_IMG_HEADER_LINK);
