            {
                ViewBag.logoSrc = "https://www.intelleges.com/mvcmt/Generic/Contents/images/MOOG_Logo.png";
            }
            else
                if (enterprise != null && enterprise.Any())
            {
                var enterpriseLogo = enterprise.FirstOrDefault();
